#include<bits/stdc++.h>
using namespace std;
int a[10005];
bool b[10005];
int m, n, c;
int main() {
	cin >> n >> m;
	for (int i = 1; i <= n; i++) {
		cin >> a[i];
		c = a[i];
		for (int j = 1; j <= a[i]; j++)
			c -= b[j];
		b[a[i]] = 1;
		a[i] = c - 1;
	}
	a[n] += m;
	for (int i = n; i > 0; i--) {
		a[i - 1] += a[i] / (n - i + 1);
		a[i] %= n - i + 1;
	}
	memset(b, 0, sizeof(b));
	for (int i = 1; i <= n; i++) {
		for (int j = 0; j <= a[i]; j++)
			if (b[j])
				a[i]++;
		cout << a[i] + 1 << " ";
		b[a[i]] = 1;
	}
	return 0;
}
